B.ZM=new A.ae("A vida n\xe3o examinada n\xe3o vale a pena ser vivida.","S\xf3crates")
B.Ys=new A.ae("S\xf3 sei que nada sei.","S\xf3crates")
B.Yh=new A.ae("Conhece-te a ti mesmo.","S\xf3crates")
B.XS=new A.ae("O segredo da mudan\xe7a \xe9 focar toda a sua energia n\xe3o em lutar contra o velho, mas em construir o novo.","S\xf3crates")
B.Yg=new A.ae("A educa\xe7\xe3o \xe9 acender uma chama, n\xe3o encher um recipiente vazio.","S\xf3crates")
B.Y0=new A.ae("Seja a mudan\xe7a que voc\xea deseja ver no mundo interior antes de exigi-la no exterior.","S\xf3crates")
B.Y2=new A.ae("A necessidade \xe9 a m\xe3e da inven\xe7\xe3o.","Plat\xe3o")
B.Yk=new A.ae("Quem aprende e aprende e n\xe3o pratica o que sabe, \xe9 como quem ara e ara e nunca semeia.","Plat\xe3o")
B.Z3=new A.ae("O come\xe7o \xe9 a parte mais importante de qualquer trabalho.","Plat\xe3o")
B.Yu=new A.ae("A opini\xe3o \xe9 a mediadora entre o conhecimento e a ignor\xe2ncia.","Plat\xe3o")
B.Z0=new A.ae("Somos o que fazemos repetidamente. Excel\xeancia, ent\xe3o, n\xe3o \xe9 um ato, mas um h\xe1bito.","Arist\xf3teles")
B.YK=new A.ae("A raiz da educa\xe7\xe3o \xe9 amarga, mas seus frutos s\xe3o doces.","Arist\xf3teles")
B.YC=new A.ae("A felicidade \xe9 o significado e o prop\xf3sito da vida, o objetivo e o fim da exist\xeancia humana.","Arist\xf3teles")
B.Yj=new A.ae("O homem s\xe1bio n\xe3o diz tudo que pensa, mas sempre pensa tudo que diz.","Arist\xf3teles")
B.Yf=new A.ae("\xc9 durante os momentos mais dif\xedceis que encontramos a verdadeira medida do car\xe1ter.","Arist\xf3teles")
B.YJ=new A.ae("A virtude \xe9 o meio-termo entre dois extremos, ambos viciosos.","Arist\xf3teles")
B.Zq=new A.ae("Devemos ser donos de nossas pr\xf3prias decis\xf5es, n\xe3o escravos das circunst\xe2ncias.","Arist\xf3teles")
B.Y8=new A.ae("Voc\xea tem poder sobre sua mente, n\xe3o sobre os eventos externos. Perceba isso e encontrar\xe1 for\xe7a.","Marco Aur\xe9lio")
B.Zx=new A.ae("A melhor vingan\xe7a \xe9 n\xe3o ser como seu inimigo.","Marco Aur\xe9lio")
B.Zg=new A.ae("Perde seu tempo quem busca a aprova\xe7\xe3o dos outros.","Marco Aur\xe9lio")
B.XG=new A.ae("Quando voc\xea acorda de manh\xe3, pense no precioso privil\xe9gio de estar vivo: respirar, pensar, desfrutar e amar.","Marco Aur\xe9lio")
B.XW=new A.ae("A qualidade da sua vida \xe9 determinada pela qualidade dos seus pensamentos.","Marco Aur\xe9lio")
B.Zh=new A.ae("Nunca estime algo como lucrativo se te for\xe7ar a quebrar sua palavra ou perder seu autorrespeito.","Marco Aur\xe9lio")
B.XJ=new A.ae("N\xe3o desperdice o resto de sua vida em pensamentos sobre outras pessoas.","Marco Aur\xe9lio")
B.Yr=new A.ae("O homem que faz tudo o que pode dentro das limita\xe7\xf5es que lhe foram impostas faz o suficiente.","Marco Aur\xe9lio")
B.YU=new A.ae("N\xe3o \xe9 o que acontece com voc\xea, mas como voc\xea reage ao que acontece com voc\xea que importa.","Epicteto")
B.YH=new A.ae("Fa\xe7a todo o poss\xedvel para n\xe3o depender de circunst\xe2ncias externas.","Epicteto")
B.YM=new A.ae("N\xe3o procure que as coisas que acontecem sejam como voc\xea quer. Deseje que as coisas que acontecem sejam como s\xe3o e voc\xea encontrar\xe1 tranquilidade.","Epicteto")
B.XB=new A.ae("Temos dois ouvidos e uma boca para que possamos ouvir duas vezes mais do que falamos.","Epicteto")
B.Y7=new A.ae("A riqueza consiste n\xe3o em ter grandes posses, mas em ter poucas necessidades.","Epicteto")
B.Yy=new A.ae("Primeiro diga a si mesmo o que voc\xea ser\xe1; depois fa\xe7a o que tem a fazer.","Epicteto")
B.ZU=new A.ae("N\xe3o \xe9 que tenhamos pouco tempo, mas que desperdi\xe7amos muito.","S\xeaneca")
B.Yt=new A.ae("Enquanto adiamos, a vida passa.","S\xeaneca")
B.Yc=new A.ae("\xc9 uma for\xe7a grande n\xe3o precisar de for\xe7a.","S\xeaneca")
B.YL=new A.ae("Retire-se para dentro de si mesmo tanto quanto puder com aqueles que v\xe3o fazer de voc\xea uma pessoa melhor.","S\xeaneca")
B.YA=new A.ae("A dificuldade que voc\xea supera hoje \xe9 a sabedoria que voc\xea carrega amanh\xe3.","S\xeaneca")
B.Z7=new A.ae("Cuide do corpo para que a mente possa habit\xe1-lo com prazer.","S\xeaneca")
B.Ye=new A.ae("Comece. N\xe3o h\xe1 nada que tanto retarde o progresso quanto esperar por ele.","S\xeaneca")
B.Yl=new A.ae("Viva com os seres humanos como se Deus te visse; fale com Deus como se os seres humanos te ouvissem.","S\xeaneca")
B.Yq=new A.ae("A mudan\xe7a \xe9 a \xfanica constante da vida.","Her\xe1clito")
B.Z5=new A.ae("N\xe3o \xe9 poss\xedvel pisar duas vezes no mesmo rio.","Her\xe1clito")
B.Zf=new A.ae("O car\xe1ter \xe9 o destino.","Her\xe1clito")
B.Z1=new A.ae("Muito aprender n\xe3o ensina a ter bom senso.","Her\xe1clito")
B.Y6=new A.ae("A jornada de mil milhas come\xe7a com um \xfanico passo.","Lao Tzu")
B.Zv=new A.ae("Aquele que se conhece \xe9 s\xe1bio. Aquele que conquista os outros \xe9 forte. Aquele que conquista a si mesmo \xe9 poderoso.","Lao Tzu")
B.XI=new A.ae("A natureza n\xe3o tem pressa, mas realiza tudo.","Lao Tzu")
B.Ze=new A.ae("Quando eu deixo de ser o que sou, torno-me o que poderia ser.","Lao Tzu")
B.Z9=new A.ae("Seja cuidadoso com seus pensamentos, eles se tornam suas palavras. Seja cuidadoso com suas palavras, elas se tornam suas a\xe7\xf5es.","Lao Tzu")
B.XV=new A.ae("Agir sem expectativa, realizar sem fazer alarde \u2014 isso \xe9 a virtude suprema.","Lao Tzu")
B.XM=new A.ae("N\xe3o importa qu\xe3o devagar voc\xea v\xe1, desde que n\xe3o pare.","Conf\xfacio")
B.XA=new A.ae("Fazer o bem por obriga\xe7\xe3o \xe9 virtude; fazer o bem por amor \xe9 sabedoria.","Conf\xfacio")
B.XU=new A.ae("A pessoa que move uma montanha come\xe7a carregando pequenas pedras.","Conf\xfacio")
B.YX=new A.ae("Escolha um trabalho que voc\xea ame e n\xe3o ter\xe1 que trabalhar um \xfanico dia em sua vida.","Conf\xfacio")
B.Zu=new A.ae("Antes de se aventurar a melhorar o mundo, d\xea tr\xeas voltas em torno de sua pr\xf3pria casa.","Conf\xfacio")
B.Z8=new A.ae("Aquele que aprende mas n\xe3o pensa est\xe1 perdido. Aquele que pensa mas n\xe3o aprende est\xe1 em grande perigo.","Conf\xfacio")
B.YZ=new A.ae("O que voc\xea pensa, voc\xea se torna. O que voc\xea sente, voc\xea atrai. O que voc\xea imagina, voc\xea cria.","Buda")
B.XQ=new A.ae("A mente \xe9 tudo. O que voc\xea pensa, voc\xea se torna.","Buda")
B.ZR=new A.ae("Tr\xeas coisas n\xe3o podem ser escondidas por muito tempo: o sol, a lua e a verdade.","Buda")
B.YI=new A.ae("N\xe3o viva no passado, n\xe3o sonhe com o futuro, concentre a mente no momento presente.","Buda")
B.ZX=new A.ae("A paz vem de dentro. N\xe3o a procure fora.","Buda")
B.Z2=new A.ae("Voc\xea mesmo, mais do que qualquer outra pessoa no universo, merece seu amor e afeto.","Buda")
B.XH=new A.ae("O que n\xe3o me mata, me fortalece.","Friedrich Nietzsche")
B.XY=new A.ae("Aquele que tem um porqu\xea para viver suporta quase qualquer como.","Friedrich Nietzsche")
B.Zz=new A.ae("A grandeza do homem est\xe1 em ser uma ponte, n\xe3o um fim.","Friedrich Nietzsche")
B.Zs=new A.ae("Sem m\xfasica a vida seria um erro.","Friedrich Nietzsche")
B.a__=new A.ae("Torne-se quem voc\xea \xe9.","Friedrich Nietzsche")
B.ZH=new A.ae("Aquele que luta com monstros deve tomar cuidado para n\xe3o se tornar um monstro.","Friedrich Nietzsche")
B.YG=new A.ae("Penso, logo existo.","Ren\xe9 Descartes")
B.ZV=new A.ae("Divida cada dificuldade em tantas partes quanto for necess\xe1rio para resolv\xea-la.","Ren\xe9 Descartes")
B.Y3=new A.ae("Age de tal forma que a m\xe1xima de tua vontade possa valer como princ\xedpio de uma legisla\xe7\xe3o universal.","Immanuel Kant")
B.XT=new A.ae("Duas coisas me enchem de admira\xe7\xe3o: o c\xe9u estrelado acima de mim e a lei moral dentro de mim.","Immanuel Kant")
B.Zw=new A.ae("Aja apenas segundo uma m\xe1xima tal que possa ao mesmo tempo querer que ela se torne uma lei universal.","Immanuel Kant")
B.XC=new A.ae("O homem est\xe1 condenado a ser livre.","Jean-Paul Sartre")
B.YN=new A.ae("A exist\xeancia precede a ess\xeancia.","Jean-Paul Sartre")
B.ZC=new A.ae("A vida n\xe3o tem sentido a priori. Antes de voc\xea viv\xea-la, ela n\xe3o \xe9 nada; cabe a voc\xea dar-lhe um sentido.","Jean-Paul Sartre")
B.XR=new A.ae("\xc9 preciso imaginar S\xedsifo feliz.","Albert Camus")
B.YQ=new A.ae("No meio do inverno aprendi, finalmente, que havia em mim um ver\xe3o invenc\xedvel.","Albert Camus")
B.ZP=new A.ae("A rebeldia \xe9 um dos \xfanicos atos humanos coerentes.","Albert Camus")
B.Y4=new A.ae("O talento acerta alvos que ningu\xe9m mais pode acertar; o g\xeanio acerta alvos que ningu\xe9m mais pode ver.","Arthur Schopenhauer")
B.ZG=new A.ae("Riqueza \xe9 como a \xe1gua do mar: quanto mais voc\xea bebe, mais sede tem.","Arthur Schopenhauer")
B.Y9=new A.ae("A paz n\xe3o \xe9 aus\xeancia de guerra; \xe9 uma virtude, um estado de esp\xedrito, uma disposi\xe7\xe3o para a benevol\xeancia, confian\xe7a e justi\xe7a.","Baruch Spinoza")
B.YP=new A.ae("O desejo \xe9 a pr\xf3pria ess\xeancia do homem.","Baruch Spinoza")
B.ZO=new A.ae("A imagina\xe7\xe3o \xe9 mais importante que o conhecimento.","Albert Einstein")
B.ZN=new A.ae("No meio de toda dificuldade h\xe1 uma oportunidade.","Albert Einstein")
B.Yx=new A.ae("A mente que se abre a uma nova ideia jamais voltar\xe1 ao seu tamanho original.","Albert Einstein")
B.YB=new A.ae("Insanidade \xe9 continuar fazendo a mesma coisa esperando resultados diferentes.","Albert Einstein")
B.Y5=new A.ae("A vida \xe9 como andar de bicicleta: para manter o equil\xedbrio \xe9 preciso continuar em movimento.","Albert Einstein")
B.XO=new A.ae("Aprenda as regras do jogo. E depois jogue melhor do que ningu\xe9m.","Albert Einstein")
B.ZB=new A.ae("Conhece o inimigo e conhece a ti mesmo; em cem batalhas nunca correr\xe1s perigo.","Sun Tzu")
B.Zc=new A.ae("Oportunidades se multiplicam quando s\xe3o aproveitadas.","Sun Tzu")
B.Z6=new A.ae("A vit\xf3ria suprema \xe9 vencer sem combater.","Sun Tzu")
B.Zi=new A.ae("Em meio ao caos existe tamb\xe9m oportunidade.","Sun Tzu")
B.Ym=new A.ae("Viva como se fosse morrer amanh\xe3. Aprenda como se fosse viver para sempre.","Mahatma Gandhi")
B.YT=new A.ae("Seja a mudan\xe7a que voc\xea deseja ver no mundo.","Mahatma Gandhi")
B.ZQ=new A.ae("A for\xe7a n\xe3o vem da capacidade f\xedsica. Vem de uma vontade indom\xe1vel.","Mahatma Gandhi")
B.XZ=new A.ae("Primeiro eles te ignoram, depois riem de voc\xea, depois lutam contra voc\xea. Ent\xe3o voc\xea vence.","Mahatma Gandhi")
B.XL=new A.ae("A maior gl\xf3ria em viver n\xe3o est\xe1 em nunca cair, mas em se levantar sempre que ca\xedmos.","Nelson Mandela")
B.ZD=new A.ae("Tudo parece imposs\xedvel at\xe9 que seja feito.","Nelson Mandela")
